/* BTTree — Figma node 2481:7383 */
/* All CSS vars verified against packages/tokens/platforms/web/bspace/dist/styles.css */

/* ── Tree root ────────────────────────────────────────────────────────────── */

.bt-tree {
  display: flex;
  flex-direction: column;
}

/* ── Tree node wrapper (row + children) ──────────────────────────────────── */

.bt-tree-node {
  display: flex;
  flex-direction: column;
}

/* ── Row — height driven by padding only, no fixed min-height ────────────── */

.bt-tree-item {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  box-sizing: border-box;
  cursor: pointer;
  user-select: none;
  padding-top: var(--space-sm);
  padding-bottom: var(--space-sm);
  padding-inline-end: var(--space-sm);
  /* padding-inline-start is set via inline style (level-based) */
}

/* ── Level-based default backgrounds ─────────────────────────────────────── */

.bt-tree-item--level-1 { background: var(--bg-primary); }
.bt-tree-item--level-2 { background: var(--color-l-grey-50); }
.bt-tree-item--level-3 { background: var(--color-l-grey-100); }
.bt-tree-item--level-4 { background: var(--color-l-grey-150); }
.bt-tree-item--level-5 { background: var(--color-l-grey-200); }
.bt-tree-item--level-6 { background: var(--color-l-grey-300); }
.bt-tree-item--level-7 { background: var(--color-l-grey-400); }
.bt-tree-item--level-8 { background: var(--color-l-grey-500); }

/* ── State overrides ─────────────────────────────────────────────────────── */

.bt-tree-item:hover:not(.bt-tree-item--disabled) {
  background: var(--bg-secondary);
}

.bt-tree-item--selected {
  background: var(--color-brand-primary-subtle);
}

.bt-tree-item--selected:hover:not(.bt-tree-item--disabled) {
  background: var(--color-brand-primary-subtle);
}

.bt-tree-item--checked {
  background: var(--color-brand-primary-subtle);
}

.bt-tree-item--checked:hover:not(.bt-tree-item--disabled) {
  background: var(--color-brand-primary-subtle);
}

/* ── Disabled ─────────────────────────────────────────────────────────────── */

.bt-tree-item--disabled {
  cursor: default;
  opacity: 0.45;
}

/* ── Arrow (expand / collapse chevron) ───────────────────────────────────── */

.bt-tree-item__arrow {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  transform: rotate(-90deg);
  transition: transform 0.15s ease;
}

.bt-tree-item__arrow--expanded {
  transform: rotate(0deg);
}

.bt-tree-item__arrow:hover {
  color: var(--text-primary);
}

.bt-tree-item__arrow-spacer {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  display: inline-block;
}

/* ── Checkbox ─────────────────────────────────────────────────────────────── */

.bt-tree-item__checkbox {
  flex-shrink: 0;
  display: flex;
  align-items: center;
}

/* ── Icon ─────────────────────────────────────────────────────────────────── */

.bt-tree-item__icon {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
}

/* ── Label (text-only content) ────────────────────────────────────────────── */

.bt-tree-item__label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: 1.14;
  color: var(--text-primary);
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ── Body (custom content slot — replaces/supplements label area) ─────────── */

.bt-tree-item__body {
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: center;
}

/* ── Children collapse / expand animation ─────────────────────────────────── */

.bt-tree-node__children {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 200ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-tree-node__children--open {
  grid-template-rows: 1fr;
}

.bt-tree-node__children-inner {
  min-height: 0;
  overflow: hidden;
}

// BTTree — Figma node 2481:7383
import './BTTree.css';
import { useState } from 'react';
import { BTCheckbox } from '../checkbox/index';
import type { BTTreeNode as BTTreeNodeType, BTTreeProps } from './BTTree.types';

/** Recursive private tree-node renderer. */
function TreeNode({ node, level }: { node: BTTreeNodeType; level: number }) {
  const [isOpen, setIsOpen] = useState(node.initiallyExpanded ?? false);
  const hasChildren = (node.children?.length ?? 0) > 0;
  const clampedLevel = Math.min(8, Math.max(1, level));
  const paddingInlineStart = `${4 + (clampedLevel - 1) * 24}px`;
  const showCheckbox = node.checkState !== undefined;

  const rowClasses = [
    'bt-tree-item',
    `bt-tree-item--level-${clampedLevel}`,
    node.selected ? 'bt-tree-item--selected' : '',
    node.checkState === 'checked' ? 'bt-tree-item--checked' : '',
    node.disabled ? 'bt-tree-item--disabled' : '',
  ]
    .filter(Boolean)
    .join(' ');

  function handleCheckChange() {
    if (node.disabled) return;
    // Standard tree behavior: unchecked → checked; checked | indeterminate → unchecked.
    const next = node.checkState === 'unchecked' ? 'checked' : 'unchecked';
    node.onCheck?.(next);
  }

  function toggleNode(next: boolean) {
    setIsOpen(next);
    node.onToggle?.(next);
  }

  return (
    <div className="bt-tree-node">
      {/* Row */}
      <div
        className={rowClasses}
        style={{ paddingInlineStart }}
        role="treeitem"
        aria-expanded={hasChildren ? isOpen : undefined}
        aria-selected={node.selected ?? false}
        onClick={() => {
          if (node.disabled) return;
          // Clicking anywhere on the row toggles expand/collapse when children exist.
          if (hasChildren) toggleNode(!isOpen);
          node.onPress?.();
        }}
      >
        {/* Arrow / spacer */}
        {hasChildren ? (
          <button
            type="button"
            className={['bt-tree-item__arrow', isOpen ? 'bt-tree-item__arrow--expanded' : '']
              .filter(Boolean)
              .join(' ')}
            aria-label={isOpen ? 'Collapse' : 'Expand'}
            onClick={(e) => {
              e.stopPropagation();
              toggleNode(!isOpen);
            }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
              <path d="M7.41 8.59L12 13.17l4.59-4.58L18 10l-6 6-6-6 1.41-1.41z" />
            </svg>
          </button>
        ) : (
          <span className="bt-tree-item__arrow-spacer" aria-hidden="true" />
        )}

        {/* Checkbox */}
        {showCheckbox && (
          <span className="bt-tree-item__checkbox" onClick={(e) => e.stopPropagation()}>
            <BTCheckbox
              checked={node.checkState === 'checked'}
              indeterminate={node.checkState === 'indeterminate'}
              disabled={node.disabled}
              onChange={handleCheckChange}
            />
          </span>
        )}

        {/* Icon */}
        {node.icon && (
          <span className="bt-tree-item__icon" aria-hidden="true">
            {node.icon}
          </span>
        )}

        {/* Body (custom content) — fills remaining row space */}
        {node.body != null ? (
          <div className="bt-tree-item__body">{node.body}</div>
        ) : (
          <span className="bt-tree-item__label">{node.label}</span>
        )}
      </div>

      {/* Children (animated via grid-template-rows) */}
      {hasChildren && (
        <div
          className={`bt-tree-node__children${isOpen ? ' bt-tree-node__children--open' : ''}`}
          role="group"
        >
          <div className="bt-tree-node__children-inner">
            {node.children!.map((child, i) => (
              <TreeNode key={child.key ?? child.label ?? i} node={child} level={level + 1} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * BTTree — recursive data-driven tree component.
 * Figma: node 2481:7383 · Category: Molecules
 *
 * @example
 * ```tsx
 * <BTTree nodes={[
 *   {
 *     label: 'Documents',
 *     initiallyExpanded: true,
 *     children: [
 *       { label: 'Reports', children: [
 *         { label: 'Q1 2026.pdf', checkState: 'checked' },
 *       ]},
 *       { label: 'Invoices', selected: true },
 *     ],
 *   },
 *   { label: 'Settings' },
 * ]} />
 * ```
 */
export function BTTree({ nodes, className }: BTTreeProps) {
  return (
    <div className={['bt-tree', className].filter(Boolean).join(' ')} role="tree">
      {nodes.map((node, i) => (
        <TreeNode key={node.key ?? node.label ?? i} node={node} level={1} />
      ))}
    </div>
  );
}
BTTree.displayName = 'BTTree';

// BTTree types — Figma node 2481:7383
import type { ReactNode } from 'react';

/** Tri-state for tree node checkboxes. */
export type BTTreeItemCheckState = 'unchecked' | 'indeterminate' | 'checked';

/**
 * Data model for a single node in the tree.
 *
 * - Provide `children` to make the node expandable (arrow is auto-shown).
 * - Omit `checkState` entirely to hide the checkbox.
 * - Either `label` or `body` (or both) should be provided for row content.
 *   When `body` is present it fills the content area; `label` still shows if
 *   you want both (e.g. label on left + badge on right via `body`).
 */
export interface BTTreeNode {
  /** Optional unique key; falls back to `label` if omitted. */
  key?: string;
  /** Row label text — optional when `body` is provided. */
  label?: string;
  /**
   * Custom content rendered in the row body area (replaces the label).
   * Receives no props — use closures to capture reactive state if needed.
   */
  body?: ReactNode;
  /** Optional 16×16 icon — any ReactNode (SVG, img, icon component). */
  icon?: ReactNode;
  /** Whether the node is initially expanded. Defaults to false. */
  initiallyExpanded?: boolean;
  /** Render with brand-subtle selected background. */
  selected?: boolean;
  /** Disable all interaction (0.45 opacity). */
  disabled?: boolean;
  /**
   * Checkbox tri-state. When `undefined` (not provided), no checkbox is shown.
   * Clicking `checked` or `indeterminate` always transitions to `unchecked`;
   * clicking `unchecked` transitions to `checked`.
   */
  checkState?: BTTreeItemCheckState;
  /** Called when the row body is clicked (not the arrow or checkbox). */
  onPress?: () => void;
  /**
   * Called when the checkbox changes. Receives `'checked'` or `'unchecked'`
   * — never `'indeterminate'`.
   */
  onCheck?: (state: 'unchecked' | 'checked') => void;
  /** Called when the expand/collapse state changes. */
  onToggle?: (expanded: boolean) => void;
  /** Child nodes — presence auto-enables the expand/collapse arrow. */
  children?: BTTreeNode[];
}

export interface BTTreeProps {
  /** Top-level tree nodes. */
  nodes: BTTreeNode[];
  className?: string;
}
